UPDATE public.questions SET
  stimulus_text = 'The use of commas is essential for clarity in writing, and it can be confusing to know when they are required.  For example, consider the following two sentences: "She went to the store.  She bought bread." These two sentences are completely independent, and they can be joined by a comma and a conjunction or by a semicolon.  However, if we rewrite the sentences so that the subject of the second sentence is a pronoun, then the rules for punctuation are slightly different.  For example, consider the following two sentences: "She went to the store. She bought it." In this case, the second sentence is dependent on the first, and it cannot be joined with a comma and a conjunction or with a semicolon alone.  Instead, we can join the sentences with a comma or we can make the second sentence a dependent clause.  Which of the following sentences illustrates a rule for punctuation in the first example?',
  question_text = 'Which of the following sentences illustrates a rule for punctuation in the first example?',
  stimulus_type = NULL,
  options = '[{"id":"A","text":"She went to the store, and she bought bread.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice A is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"B","text":"She went to the store; she bought bread.","is_correct":true,"explanation":"The first example states that two independent sentences can be joined by a semicolon. Only choice B illustrates this rule because it uses a semicolon to join two independent clauses.  Choice A illustrates the rule that two independent sentences can be joined by a comma and a conjunction.  Choice C i. Choice B matches the question''s requirement and is consistent with the passage''s central claim or supporting detail. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"C","text":"She went to the store, but she bought bread.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice C is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."},{"id":"D","text":"She went to the store; bread was what she bought.","is_correct":false,"explanation":"This choice does not follow from the information given or contains a calculation error. Choice D is incorrect because it either misreads the passage, overgeneralizes a limited detail, or focuses on information irrelevant to the question stem. Re-read the sentences surrounding the key detail before eliminating this option on test day."}]'::jsonb,
  correct_answer = 'B',
  explanation = 'The first example states that two independent sentences can be joined by a semicolon. Only choice B illustrates this rule because it uses a semicolon to join two independent clauses.  Choice A illustrates the rule that two independent sentences can be joined by a comma and a conjunction.  Choice C illustrates a rule for joining two sentences that have opposing ideas.  Choice D incorrectly combines the independent clause with the dependent clause. The passage states that "The use of commas is essential for clarity in writing, and it can be confusing to know when they are required. For examp…", which is the textual anchor for eliminating weaker choices. Choice B is correct because it aligns with that evidence: She went to the store; she bought bread.. Each incorrect option either contradicts a explicit detail, imports information not present in the text, or answers a different question than the one asked.',
